import React, { useState } from "react";
import {
  AppBar,
  Toolbar,
  Typography,
  Button,
  Box,
  Avatar,
  Menu,
  MenuItem,
  Divider,
} from "@mui/material";
import { Link, useNavigate } from "react-router-dom";
import LocalHospitalIcon from "@mui/icons-material/LocalHospital";
import PersonIcon from "@mui/icons-material/Person";

const PRIMARY = "#1976d2";
const PRIMARY_DARK = "#1565c0";

const Navbar = () => {
  const navigate = useNavigate();
  const isPatientLoggedIn =
    localStorage.getItem("isPatientLoggedIn") === "true";
  const patientName = localStorage.getItem("patientName") || "Patient";
  const [anchorEl, setAnchorEl] = useState(null);

  const handleLogout = () => {
    localStorage.removeItem("isPatientLoggedIn");
    localStorage.removeItem("patientName");
    localStorage.removeItem("patientEmail");
    setAnchorEl(null);
    navigate("/");
  };

  return (
    <AppBar
      position="static"
      elevation={0}
      sx={{
        background: `linear-gradient(90deg, ${PRIMARY_DARK} 0%, ${PRIMARY} 100%)`,
        borderBottom: "1px solid rgba(255,255,255,0.1)",
      }}
    >
      <Toolbar sx={{ px: { xs: 2, md: 4 } }}>
        {/* Logo */}
        <Box
          component={Link}
          to="/"
          sx={{
            display: "flex",
            alignItems: "center",
            gap: 1,
            textDecoration: "none",
            flexGrow: 1,
          }}
        >
          <LocalHospitalIcon sx={{ color: "white", fontSize: 28 }} />
          <Typography
            variant="h6"
            sx={{
              color: "white",
              fontWeight: 800,
              letterSpacing: "-0.5px",
              fontSize: { xs: 16, md: 20 },
            }}
          >
            Medi<span style={{ color: "#90caf9" }}>Care</span>
          </Typography>
        </Box>

        {/* Nav Links */}
        <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
          <Button
            color="inherit"
            component={Link}
            to="/"
            sx={{ fontWeight: 500, fontSize: 14 }}
          >
            Hospitals
          </Button>

          {isPatientLoggedIn ? (
            <>
              <Button
                color="inherit"
                component={Link}
                to="/patient/dashboard"
                sx={{ fontWeight: 500, fontSize: 14 }}
              >
                My Dashboard
              </Button>
              <Box
                sx={{ ml: 1, cursor: "pointer" }}
                onClick={(e) => setAnchorEl(e.currentTarget)}
              >
                <Avatar
                  sx={{
                    width: 36,
                    height: 36,
                    bgcolor: "rgba(255,255,255,0.2)",
                    fontSize: 14,
                    fontWeight: 700,
                    border: "2px solid rgba(255,255,255,0.4)",
                  }}
                >
                  {patientName.charAt(0).toUpperCase()}
                </Avatar>
              </Box>
              <Menu
                anchorEl={anchorEl}
                open={Boolean(anchorEl)}
                onClose={() => setAnchorEl(null)}
                PaperProps={{
                  sx: {
                    borderRadius: 3,
                    mt: 1,
                    minWidth: 180,
                    boxShadow: "0 8px 32px rgba(0,0,0,0.12)",
                  },
                }}
              >
                <Box sx={{ px: 2, py: 1.5 }}>
                  <Typography variant="body2" fontWeight={700}>
                    {patientName}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    Patient Account
                  </Typography>
                </Box>
                <Divider />
                <MenuItem
                  onClick={() => {
                    navigate("/patient/dashboard");
                    setAnchorEl(null);
                  }}
                >
                  <PersonIcon sx={{ fontSize: 18, mr: 1, color: PRIMARY }} /> My
                  Dashboard
                </MenuItem>
                <MenuItem onClick={handleLogout} sx={{ color: "error.main" }}>
                  🚪 Logout
                </MenuItem>
              </Menu>
            </>
          ) : (
            <>
              <Button
                color="inherit"
                component={Link}
                to="/patient/login"
                sx={{ fontWeight: 500, fontSize: 14 }}
              >
                Login
              </Button>
              <Button
                variant="outlined"
                component={Link}
                to="/patient/login"
                sx={{
                  color: "white",
                  borderColor: "rgba(255,255,255,0.5)",
                  fontWeight: 600,
                  fontSize: 13,
                  borderRadius: 2,
                  "&:hover": {
                    borderColor: "white",
                    bgcolor: "rgba(255,255,255,0.1)",
                  },
                }}
              >
                Register
              </Button>
            </>
          )}
        </Box>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
